import React, { useState, useEffect } from "react";
import api from "../api/api"; 
import "bootstrap/dist/css/bootstrap.min.css";
import { 
  FaSearch, FaCartPlus, FaUser, FaTrash, 
  FaPhoneAlt, FaFileInvoiceDollar, FaPrint, FaIdCard 
} from "react-icons/fa";

export default function Cotizaciones() {
  const [productos, setProductos] = useState([]);
  
  // Estados para búsqueda
  const [busquedaProducto, setBusquedaProducto] = useState("");
  const [productosFiltrados, setProductosFiltrados] = useState([]);
  const [productoSeleccionado, setProductoSeleccionado] = useState(null);
  
  // ✅ ESTADO UNIFICADO DEL CLIENTE (Nivel Profesional)
  const [cliente, setCliente] = useState({
    nombre: "",
    apellido: "",
    correo: "",
    telefono: "",
    dui: ""
  });
  
  // Estados de la Cotización
  const [cantidad, setCantidad] = useState(1);
  const [mensaje, setMensaje] = useState("");
  const [carrito, setCarrito] = useState([]);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    cargarDatos();
  }, []);

  const cargarDatos = async () => {
    try {
      const resProd = await api.get("/productos");
      setProductos(resProd.data);
    } catch (err) {
      console.error("❌ Error al cargar datos:", err);
    }
  };

  const manejarBusqueda = (texto) => {
    setBusquedaProducto(texto);
    if (!texto.trim()) return setProductosFiltrados([]);
    const coincidencias = productos.filter((p) =>
      (p.nombre || "").toLowerCase().includes(texto.toLowerCase())
    );
    setProductosFiltrados(coincidencias);
  };

  const seleccionarProducto = (p) => {
    setProductoSeleccionado(p);
    setBusquedaProducto(p.nombre);
    setProductosFiltrados([]); 
    setCantidad(1);
  };

  const agregarAlCarrito = () => {
    if (!productoSeleccionado || cantidad <= 0) return;

    const prodID = productoSeleccionado._id; 
    const stockActual = Number(productoSeleccionado.stock || 0);

    if (stockActual < cantidad) {
      alert(`⚠️ Nota: Stock bajo (${stockActual}). Se incluirá en la cotización.`);
    }

    const existente = carrito.find((p) => p.ProductID === prodID);
    if (existente) {
      setCarrito(carrito.map((p) => 
        p.ProductID === prodID ? { ...p, Cantidad: p.Cantidad + cantidad } : p
      ));
    } else {
      setCarrito([...carrito, {
        ProductID: prodID,
        Nombre: productoSeleccionado.nombre,
        Cantidad: cantidad,
        PrecioUnitario: Number(productoSeleccionado.precio)
      }]);
    }

    setProductoSeleccionado(null);
    setBusquedaProducto("");
    setMensaje("✅ Añadido a la cotización");
    setTimeout(() => setMensaje(""), 1500);
  };

  const totales = () => {
    const subtotal = carrito.reduce((acc, p) => acc + p.Cantidad * p.PrecioUnitario, 0);
    const iva = subtotal * 0.13;
    return { subtotal, iva, total: subtotal + iva };
  };

  const guardarCotizacion = async (e) => {
    e.preventDefault();
    if (!cliente.nombre.trim() || carrito.length === 0) {
      return setMensaje("⚠️ Ingresa el nombre del cliente y agrega productos.");
    }

    setLoading(true);
    setMensaje("⏳ Guardando cotización...");

    try {
      const payload = {
        ...cliente, // Enviamos el objeto cliente completo
        productos: carrito.map((p) => ({
          ProductID: p.ProductID, 
          Nombre: p.Nombre,
          Cantidad: p.Cantidad,
          PrecioUnitario: p.PrecioUnitario
        })),
        Subtotal: totales().subtotal,
        IVA: totales().iva,
        Total: totales().total
      };

      await api.post("/cotizaciones", payload);

      setMensaje("📝 ¡Cotización guardada exitosamente!");
      setCarrito([]);
      setCliente({ nombre: "", apellido: "", correo: "", telefono: "", dui: "" });
      
    } catch (err) {
      setMensaje("❌ Error de red: No se pudo conectar con el servidor.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="container-fluid p-4 bg-light min-vh-100 pb-5" style={{ marginLeft: "250px", width: "calc(100% - 250px)" }}>
      <div className="d-flex align-items-center mb-4">
        <FaFileInvoiceDollar className="fs-2 text-primary me-3" />
        <h2 className="fw-bold mb-0 text-dark">Nueva Cotización - Tienda Barrios</h2>
      </div>

      <div className="row g-4">
        <div className="col-lg-7">
          <div className="card shadow-sm border-0 p-4 mb-4 rounded-4 bg-white">
            <h5 className="fw-bold text-dark mb-3"><FaSearch className="me-2 text-primary" /> 1. Buscar Productos</h5>
            <div className="position-relative mb-3">
              <input
                type="text"
                className="form-control border-0 bg-light p-3 shadow-none"
                placeholder="Escribe el nombre del repuesto..."
                value={busquedaProducto}
                onChange={(e) => manejarBusqueda(e.target.value)}
              />
              {productosFiltrados.length > 0 && (
                <ul className="list-group position-absolute w-100 shadow-lg mt-1" style={{ zIndex: 1000, maxHeight: "200px", overflowY: "auto" }}>
                  {productosFiltrados.map((p) => (
                    <li key={p._id} className="list-group-item list-group-item-action d-flex justify-content-between" style={{ cursor: "pointer" }} onClick={() => seleccionarProducto(p)}>
                      <span className="fw-bold">{p.nombre}</span>
                      <span className="badge bg-secondary rounded-pill">${p.precio}</span>
                    </li>
                  ))}
                </ul>
              )}
            </div>

            {productoSeleccionado && (
              <div className="alert alert-dark border-0 d-flex justify-content-between align-items-center animate__animated animate__fadeIn">
                <div>
                  <h6 className="mb-0 fw-bold">{productoSeleccionado.nombre}</h6>
                  <small>Precio Unitario: ${productoSeleccionado.precio}</small>
                </div>
                <div className="d-flex gap-2 align-items-center">
                  <input type="number" className="form-control form-control-sm text-center" style={{ width: "60px" }} value={cantidad} onChange={(e) => setCantidad(Number(e.target.value))} min="1" />
                  <button className="btn btn-primary btn-sm fw-bold" onClick={agregarAlCarrito}><FaCartPlus /> Añadir</button>
                </div>
              </div>
            )}

            <h5 className="fw-bold text-dark mb-3 mt-4"><FaUser className="me-2 text-primary" /> 2. Información del Cliente</h5>
            <div className="row g-3">
              <div className="col-md-6">
                <label className="small fw-bold text-muted">Nombre *</label>
                <input className="form-control bg-light border-0" value={cliente.nombre} onChange={(e) => setCliente({...cliente, nombre: e.target.value})} required/>
              </div>
              <div className="col-md-6">
                <label className="small fw-bold text-muted">Apellido</label>
                <input className="form-control bg-light border-0" value={cliente.apellido} onChange={(e) => setCliente({...cliente, apellido: e.target.value})} />
              </div>
              <div className="col-md-6">
                <label className="small fw-bold text-muted">DUI/NIT</label>
                <div className="input-group">
                  <span className="input-group-text bg-light border-0"><FaIdCard /></span>
                  <input className="form-control bg-light border-0" placeholder="00000000-0" value={cliente.dui} onChange={(e) => setCliente({...cliente, dui: e.target.value})} />
                </div>
              </div>
              <div className="col-md-6">
                <label className="small fw-bold text-muted">Teléfono</label>
                <div className="input-group">
                  <span className="input-group-text bg-light border-0"><FaPhoneAlt /></span>
                  <input className="form-control bg-light border-0" value={cliente.telefono} onChange={(e) => setCliente({...cliente, telefono: e.target.value})} />
                </div>
              </div>
            </div>
            {mensaje && <div className={`alert mt-4 fw-bold border-0 shadow-sm ${mensaje.includes('❌') ? 'alert-danger' : 'alert-success'}`}>{mensaje}</div>}
          </div>
        </div>

        <div className="col-lg-5">
          <div className="card shadow-sm border-0 p-4 bg-white h-100 rounded-4 d-flex flex-column">
            <h5 className="fw-bold text-dark mb-3 border-bottom pb-3">📑 Resumen de Cotización</h5>
            <div className="table-responsive flex-grow-1">
              <table className="table table-hover table-sm">
                <thead>
                  <tr className="small text-muted">
                    <th>PRODUCTO</th>
                    <th className="text-center">CANT.</th>
                    <th className="text-end">TOTAL</th>
                    <th></th>
                  </tr>
                </thead>
                <tbody>
                  {carrito.length === 0 ? (
                    <tr><td colSpan="4" className="text-center py-5 text-muted">Agregue productos para cotizar</td></tr>
                  ) : (
                    carrito.map((p) => (
                      <tr key={p.ProductID} className="align-middle">
                        <td className="small fw-bold">{p.Nombre}</td>
                        <td className="text-center"><span className="badge bg-light text-dark border">{p.Cantidad}</span></td>
                        <td className="text-end fw-bold text-primary">${(p.Cantidad * p.PrecioUnitario).toFixed(2)}</td>
                        <td className="text-end"><button className="btn btn-link text-danger p-0" onClick={() => setCarrito(carrito.filter(i => i.ProductID !== p.ProductID))}><FaTrash /></button></td>
                      </tr>
                    ))
                  )}
                </tbody>
              </table>
            </div>

            <div className="mt-auto pt-3 border-top">
              <div className="d-flex justify-content-between mb-1"><span>Subtotal:</span><span>${totales().subtotal.toFixed(2)}</span></div>
              <div className="d-flex justify-content-between mb-1"><span>IVA (13%):</span><span>${totales().iva.toFixed(2)}</span></div>
              <div className="d-flex justify-content-between fs-3 fw-bold text-primary"><span>TOTAL:</span><span>${totales().total.toFixed(2)}</span></div>
              
              <button 
                className="btn btn-primary btn-lg w-100 mt-4 shadow fw-bold py-3 rounded-pill d-flex align-items-center justify-content-center" 
                onClick={guardarCotizacion} 
                disabled={carrito.length === 0 || loading}
              >
                {loading ? <span className="spinner-border spinner-border-sm me-2"></span> : <FaPrint className="me-2"/>}
                GENERAR COTIZACIÓN
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
